class Solution:
    def removeKdigits(self, num, k):
        # independent brute force over which positions to keep, for small inputs:
        # choose len(num)-k positions in order forming the smallest number.
        keep = len(num) - k
        if keep <= 0:
            return '0'
        res = []
        start = 0
        for i in range(keep):
            # pick the smallest digit in the window that still leaves enough room
            end = len(num) - (keep - i - 1)
            best = start
            for j in range(start, end):
                if num[j] < num[best]:
                    best = j
            res.append(num[best])
            start = best + 1
        s = ''.join(res).lstrip('0')
        return s if s else '0'

