class Solution:
    def removeKdigits(self, num, k):
        stack = []
        for c in num:
            while k > 0 and stack and stack[-1] > c:
                stack.pop()
                k -= 1
            stack.append(c)
        if k > 0:
            stack = stack[:-k]
        s = ''.join(stack).lstrip('0')
        return s if s else '0'

