var removeKdigits = function(num, k) {
    const stack = [];
    for (const c of num) {
        while (k > 0 && stack.length && stack[stack.length - 1] > c) {
            stack.pop();
            k -= 1;
        }
        stack.push(c);
    }
    if (k > 0) stack.length -= k;
    const s = stack.join('').replace(/^0+/, '');
    return s.length ? s : '0';
};
